create table "c15t_subject" ("id" varchar(255) not null primary key, "externalId" text, "identityProvider" text, "createdAt" timestamp default CURRENT_TIMESTAMP not null, "updatedAt" timestamp default CURRENT_TIMESTAMP not null, "tenantId" text);

create table "c15t_domain" ("id" varchar(255) not null primary key, "name" text not null, "createdAt" timestamp default CURRENT_TIMESTAMP not null, "updatedAt" timestamp default CURRENT_TIMESTAMP not null, "tenantId" text);

create table "c15t_consentPolicy" ("id" varchar(255) not null primary key, "version" text not null, "type" text not null, "hash" text, "effectiveDate" timestamp not null, "isActive" boolean not null, "createdAt" timestamp default CURRENT_TIMESTAMP not null, "tenantId" text);

create table "c15t_runtimePolicyDecision" ("id" varchar(255) not null primary key, "tenantId" text, "policyId" text not null, "fingerprint" text not null, "matchedBy" text not null, "countryCode" text, "regionCode" text, "jurisdiction" text not null, "language" text, "model" text not null, "policyI18n" json, "uiMode" text, "bannerUi" json, "dialogUi" json, "categories" json, "preselectedCategories" json, "proofConfig" json, "dedupeKey" text not null, "createdAt" timestamp default CURRENT_TIMESTAMP not null);

alter table "c15t_runtimePolicyDecision" add constraint "unique_c_runtimePolicyDecision_dedupeKey" unique ("dedupeKey");

create table "c15t_consentPurpose" ("id" varchar(255) not null primary key, "code" text not null, "createdAt" timestamp default CURRENT_TIMESTAMP not null, "updatedAt" timestamp default CURRENT_TIMESTAMP not null, "tenantId" text);

create table "c15t_consent" ("id" varchar(255) not null primary key, "subjectId" text not null, "domainId" text not null, "policyId" text, "purposeIds" json not null, "metadata" json, "ipAddress" text, "userAgent" text, "givenAt" timestamp default CURRENT_TIMESTAMP not null, "validUntil" timestamp, "jurisdiction" text, "jurisdictionModel" text, "tcString" text, "uiSource" text, "consentAction" text, "runtimePolicyDecisionId" text, "runtimePolicySource" text, "tenantId" text, constraint "consent_subject_subject_fk" foreign key ("subjectId") references "c15t_subject" ("id") on delete restrict on update restrict, constraint "consent_domain_domain_fk" foreign key ("domainId") references "c15t_domain" ("id") on delete restrict on update restrict, constraint "consent_consentPolicy_policy_fk" foreign key ("policyId") references "c15t_consentPolicy" ("id") on delete restrict on update restrict, constraint "consent_runtimePolicyDecision_runtimePolicyDecision_fk" foreign key ("runtimePolicyDecisionId") references "c15t_runtimePolicyDecision" ("id") on delete restrict on update restrict);

create table "c15t_auditLog" ("id" varchar(255) not null primary key, "entityType" text not null, "entityId" text not null, "actionType" text not null, "subjectId" text, "ipAddress" text, "userAgent" text, "changes" json, "metadata" json, "createdAt" timestamp default CURRENT_TIMESTAMP not null, "tenantId" text, constraint "auditLog_subject_subject_fk" foreign key ("subjectId") references "c15t_subject" ("id") on delete restrict on update restrict);

create table "private_c15t_settings" ("key" varchar(255) primary key, "value" text not null);

