-- RLS hardening (applied separately): block anon/PostgREST access; the
-- self-hosted backend connects via the direct Postgres role and bypasses RLS.
alter table "c15t_subject" enable row level security;
alter table "c15t_domain" enable row level security;
alter table "c15t_consentPolicy" enable row level security;
alter table "c15t_runtimePolicyDecision" enable row level security;
alter table "c15t_consentPurpose" enable row level security;
alter table "c15t_consent" enable row level security;
alter table "c15t_auditLog" enable row level security;
alter table "private_c15t_settings" enable row level security;
